def solve(grid: Array[Array[Long]], k: Long): Long = {
    val m = grid.length
    if (m == 0) return 0
    val n = grid(0).length
    var visited = Array.ofDim[Boolean](m, n)
    var count = 0L

    def dfs(i: Int, j: Int): Long = {
        if (i < 0 || i >= m || j < 0 || j >= n || grid(i)(j) == 0 || visited(i)(j)) {
            return 0L
        }
        visited(i)(j) = true
        var sum = grid(i)(j)
        sum += dfs(i + 1, j)
        sum += dfs(i - 1, j)
        sum += dfs(i, j + 1)
        sum += dfs(i, j - 1)
        sum
    }

    for (i <- 0 until m) {
        for (j <- 0 until n) {
            if (grid(i)(j) != 0 && !visited(i)(j)) {
                val sum = dfs(i, j)
                if (sum % k == 0) {
                    count += 1
                }
            }
        }
    }

    count
}
